import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';

function Navbar() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const { theme, toggleTheme } = useTheme();

  const getInitials = (name) => {
    if (!name) return '?';
    return name
      .split(' ')
      .map((n) => n[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  return (
    <nav className="navbar">
      <div className="navbar-left">
        <div className="cloud-logo">
          <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M19.35 10.04C18.67 6.59 15.64 4 12 4C9.11 4 6.6 5.64 5.35 8.04C2.34 8.36 0 10.91 0 14C0 17.31 2.69 20 6 20H19C21.76 20 24 17.76 24 15C24 12.36 21.95 10.22 19.35 10.04ZM19 18H6C3.79 18 2 16.21 2 14C2 11.95 3.53 10.24 5.58 10.05C5.78 7.76 7.75 6 10 6H11.07C11.16 6 11.24 6 11.33 6.01C12.08 3.69 14.18 2 16.67 2C19.54 2 21.89 4.34 21.98 7.23C22.26 7.12 22.55 7.05 22.86 7.05C23.57 7.05 24.2 7.34 24.66 7.82C24.18 4.47 21.47 2 18.35 2C15.33 2 12.8 4.3 12.36 7.18C11.65 6.72 10.79 6.45 9.85 6.45C7.13 6.45 5 8.58 5 11.3C5 11.66 5.05 12 5.14 12.34C5.05 12.36 4.96 12.38 4.87 12.4C4.5 12.5 3.95 12.5 3.95 12.5C2.83 12.5 2 13.33 2 14.45C2 15.57 2.83 16.4 3.95 16.4H19.35C21.03 16.4 22.4 15.03 22.4 13.35C22.4 11.67 21.03 10.3 19.35 10.3C19.05 10.3 18.76 10.33 18.48 10.38C18.21 10.25 17.91 10.18 17.59 10.18C16.47 10.18 15.54 11.11 15.54 12.23C15.54 13.35 16.47 14.28 17.59 14.28C18.28 14.28 18.87 13.5 18.87 13.5" fill="var(--primary)"/>
            <rect x="17" y="13" width="3" height="3" rx="0.5" fill="var(--bg)"/>
          </svg>
        </div>
      </div>
      <div className="navbar-right">
        {user ? (
          <>
            <button
              className="navbar-btn"
              onClick={() => navigate('/settings')}
              title="Manage Account"
            >
              <i className="fa-solid fa-user-gear"></i>
              <span>Manage Account</span>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="User Profile"
            >
              <div className="user-avatar">
                {getInitials(user.fullName)}
              </div>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={() => navigate('/settings')}
              title="Settings"
            >
              <i className="fa-solid fa-gear"></i>
            </button>

            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="navbar-btn"
              onClick={logout}
              title="Sign Out"
            >
              <i className="fa-solid fa-right-from-bracket"></i>
              <span>Sign Out</span>
            </button>
          </>
        ) : (
          <>
            <button
              className="navbar-btn navbar-btn-icon"
              onClick={toggleTheme}
              title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
            >
              <i className={`fa-solid ${theme === 'light' ? 'fa-moon' : 'fa-sun'}`}></i>
            </button>

            <button
              className="btn btn-primary"
              onClick={() => navigate('/auth')}
              style={{ borderRadius: '20px', padding: '6px 18px', fontSize: '13px', fontWeight: 500 }}
            >
              <i className="fa-solid fa-user" style={{ fontSize: '13px' }}></i>
              <span>Sign In</span>
            </button>
          </>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
